// T112 FeeCalculatorHandler — CORRECT inline-pure pattern
@Injectable()
export class FeeCalculatorHandler {
  async calculate(input: FeeInput): Promise<DataProcessResult<FeeBreakdown>> {
    const baseFee = input.grossAmount * 0.029; // from FREEDOM config
    const platformFee = input.grossAmount * 0.02; // from FREEDOM config
    const totalFee = baseFee + platformFee;
    // Returns FeeBreakdown ONLY — no storeDocument, no enqueue
    return DataProcessResult.success({
      baseFee,
      platformFee,
      totalFee,
      netAmount: input.grossAmount - totalFee,
    });
  }
}
